package com.multilanglearner.data.network

import android.media.MediaMetadataRetriever
import android.util.Log
import com.multilanglearner.domain.model.AIConfig
import com.multilanglearner.domain.model.WordTimestamp
import kotlinx.coroutines.*
import java.io.File
import javax.inject.Inject
import javax.inject.Singleton

/**
 * 分段转录服务 - 处理大视频文件的转录
 * 对于超大文件，提供用户友好的处理建议
 */
@Singleton
class SegmentedWhisperService @Inject constructor(
    private val whisperService: WhisperService
) {
    companion object {
        private const val TAG = "SegmentedWhisper"
        // Groq API 文件大小限制
        private const val MAX_FILE_SIZE = 100 * 1024 * 1024L // 100MB
        // 建议分段处理的文件大小阈值
        private const val SUGGEST_SEGMENT_SIZE = 150 * 1024 * 1024L // 150MB
        // 最小文件大小
        private const val MIN_FILE_SIZE = 1024L // 1KB
    }

    private val serviceScope = CoroutineScope(Dispatchers.IO + SupervisorJob())

    /**
     * 转录视频文件 - 支持大文件处理
     * @param videoFile 视频文件
     * @param config AI配置
     * @param onProgress 进度回调
     * @return 转录结果
     */
    suspend fun transcribeSegmented(
        videoFile: File,
        config: AIConfig,
        onProgress: (Int, Int, Int, String) -> Unit = { _, _, _, _ -> }
    ): WhisperResult? = withContext(Dispatchers.IO) {
        try {
            val fileSize = videoFile.length()
            val fileSizeMB = String.format("%.2f", fileSize / 1024.0 / 1024.0)

            Log.d(TAG, "Starting transcription: file=${videoFile.name}, size=$fileSizeMB MB")
            onProgress(1, 1, 10, "准备转录...")

            // 检查最小文件大小
            if (fileSize < MIN_FILE_SIZE) {
                Log.e(TAG, "File too small: $fileSize bytes")
                return@withContext WhisperResult(
                    success = false,
                    error = "❌ 视频文件过小\n\n文件大小: ${fileSize / 1024} KB\n最小要求: 1 KB\n\n请使用包含音频内容的有效视频文件"
                )
            }

            // 获取视频时长
            val duration = getVideoDuration(videoFile)
            if (duration == null) {
                Log.e(TAG, "Failed to get video duration")
                return@withContext WhisperResult(
                    success = false,
                    error = "❌ 无法读取视频信息\n\n请确保视频文件完整且可播放\n\n支持的格式: MP4, WebM, MKV"
                )
            }

            val durationMinutes = String.format("%.1f", duration / 60.0)
            Log.d(TAG, "Video duration: ${durationMinutes} minutes (${duration} seconds)")

            // 根据文件大小决定处理方式
            when {
                fileSize <= MAX_FILE_SIZE -> {
                    // 文件在限制内，直接转录
                    Log.d(TAG, "File within API limit, transcribing directly")
                    onProgress(1, 1, 20, "文件大小合适，直接转录...")
                    whisperService.transcribeGroq(videoFile, config)
                }

                fileSize <= SUGGEST_SEGMENT_SIZE -> {
                    // 文件略超限制，尝试直接转录（Groq 可能支持更大文件）
                    Log.d(TAG, "File slightly exceeds documented limit, attempting direct transcription")
                    onProgress(1, 1, 20, "尝试直接转录...")

                    val result = whisperService.transcribeGroq(videoFile, config)

                    if (result?.success == true) {
                        result
                    } else {
                        // 如果直接转录失败，提供详细建议
                        val errorMsg = result?.error ?: "未知错误"
                        WhisperResult(
                            success = false,
                            error = "❌ 文件过大，转录失败\n\n$fileSizeMB MB 超过了 API 限制\n\n建议解决方案：\n\n" +
                                "Option 1: Split with FFmpeg on PC\n" +
                                "1. Download FFmpeg: https://ffmpeg.org\n" +
                                "2. Extract segments:\n" +
                                "   ffmpeg -i input.mp4 -t 300 part1.mp4\n" +
                                "   ffmpeg -i input.mp4 -ss 295 -t 300 part2.mp4\n" +
                                "3. Transcribe each part separately\n\n" +
                                "Option 2: Compress video\n" +
                                "ffmpeg -i input.mp4 -b:a 64k output.mp4\n\n" +
                                "Error: $errorMsg"
                        )
                    }
                }

                else -> {
                    // 文件太大，提供详细指导
                    Log.d(TAG, "File too large for direct processing")
                    WhisperResult(
                        success = false,
                        error = "❌ 文件过大，无法直接转录\n\n" +
                            "文件信息：\n" +
                            "Size: $fileSizeMB MB\n" +
                            "Duration: ${durationMinutes} minutes\n\n" +
                            "Solutions:\n\n" +
                            "[Recommended] Option 1: Split with FFmpeg on PC\n" +
                            "1. Install FFmpeg: https://ffmpeg.org\n" +
                            "2. Extract 5-minute segments:\n" +
                            "   ffmpeg -i video.mp4 -t 300 segment_01.mp4\n" +
                            "   ffmpeg -i video.mp4 -ss 295 -t 305 segment_02.mp4\n" +
                            "3. Import each segment to transcribe\n\n" +
                            "Option 2: Compress video\n" +
                            "ffmpeg -i video.mp4 -c:v libx264 -crf 28 -c:a aac -b:a 64k output.mp4\n\n" +
                            "Option 3: Extract audio only\n" +
                            "ffmpeg -i video.mp4 -vn -b:a 64k audio.mp4"
                    )
                }
            }

        } catch (e: Exception) {
            Log.e(TAG, "Transcription error", e)
            WhisperResult(
                success = false,
                error = "❌ 转录失败\n\n${e.message}"
            )
        }
    }

    /**
     * 获取视频时长（秒）- 使用 Android 原生 API
     */
    private fun getVideoDuration(videoFile: File): Double? {
        val retriever = MediaMetadataRetriever()
        return try {
            retriever.setDataSource(videoFile.absolutePath)
            val durationStr = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_DURATION)
            durationStr?.toDoubleOrNull()?.let { it / 1000.0 }
        } catch (e: Exception) {
            Log.e(TAG, "Error getting video duration", e)
            null
        } finally {
            try {
                retriever.release()
            } catch (e: Exception) {
                Log.e(TAG, "Error releasing retriever", e)
            }
        }
    }

    /**
     * 获取视频文件的详细信息
     */
    fun getVideoInfo(videoFile: File): VideoInfo? {
        val retriever = MediaMetadataRetriever()
        return try {
            retriever.setDataSource(videoFile.absolutePath)

            val duration = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_DURATION)
                ?.toDoubleOrNull()?.div(1000.0)
            val width = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_VIDEO_WIDTH)
                ?.toIntOrNull()
            val height = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_VIDEO_HEIGHT)
                ?.toIntOrNull()
            val bitrate = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_BITRATE)
                ?.toIntOrNull()
            val rotation = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_VIDEO_ROTATION)
                ?.toIntOrNull() ?: 0

            VideoInfo(
                duration = duration,
                width = width,
                height = height,
                bitrate = bitrate,
                rotation = rotation,
                fileSize = videoFile.length()
            )
        } catch (e: Exception) {
            Log.e(TAG, "Error getting video info", e)
            null
        } finally {
            try {
                retriever.release()
            } catch (e: Exception) {
                Log.e(TAG, "Error releasing retriever", e)
            }
        }
    }
}

/**
 * 视频信息数据类
 */
data class VideoInfo(
    val duration: Double?,      // 时长（秒）
    val width: Int?,            // 宽度
    val height: Int?,           // 高度
    val bitrate: Int?,          // 比特率
    val rotation: Int,          // 旋转角度
    val fileSize: Long          // 文件大小
)

package com.multilanglearner.service

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.app.Service
import android.content.Context
import android.content.Intent
import android.os.Binder
import android.os.Build
import android.os.IBinder
import android.util.Log
import androidx.core.app.NotificationCompat
import com.multilanglearner.R
import com.multilanglearner.data.network.FFmpegSegmentedTranscriptionService
import com.multilanglearner.data.network.WhisperResult
import com.multilanglearner.data.store.AIConfigStore
import com.multilanglearner.domain.model.WordTimestamp
import com.multilanglearner.domain.util.VttParser
import dagger.hilt.android.AndroidEntryPoint
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.first
import kotlinx.serialization.builtins.ListSerializer
import kotlinx.serialization.json.Json
import java.io.File
import javax.inject.Inject

/**
 * 转录前台服务
 * 允许用户离开页面后继续转录
 */
@AndroidEntryPoint
class TranscriptionService : Service() {
    companion object {
        private const val TAG = "TranscriptionService"
        private const val CHANNEL_ID = "transcription_channel"
        private const val CHANNEL_NAME = "视频转录"
        private const val NOTIFICATION_ID = 1001

        const val ACTION_START = "com.multilanglearner.ACTION_START_TRANSCRIPTION"
        const val ACTION_CANCEL = "com.multilanglearner.ACTION_CANCEL_TRANSCRIPTION"
        const val ACTION_OPEN = "com.multilanglearner.ACTION_OPEN_PLAYER"

        const val EXTRA_VIDEO_PATH = "video_path"
        const val EXTRA_VIDEO_NAME = "video_name"

        // 进度广播
        const val ACTION_PROGRESS = "com.multilanglearner.TRANSCRIPTION_PROGRESS"
        const val EXTRA_SEGMENT = "segment"
        const val EXTRA_TOTAL = "total"
        const val EXTRA_PROGRESS = "progress"
        const val EXTRA_MESSAGE = "message"
        const val EXTRA_REMAINING = "remaining"

        // 队列状态广播
        const val ACTION_QUEUE_UPDATE = "com.multilanglearner.TRANSCRIPTION_QUEUE_UPDATE"
        const val EXTRA_QUEUE_SIZE = "queue_size"
        const val EXTRA_CURRENT_VIDEO = "current_video"
        const val EXTRA_QUEUE_LIST = "queue_list"

        // 完成广播
        const val ACTION_COMPLETED = "com.multilanglearner.TRANSCRIPTION_COMPLETED"
        const val EXTRA_SUCCESS = "success"
        const val EXTRA_ERROR = "error"
        const val EXTRA_SUBTITLE_COUNT = "subtitle_count"
        const val EXTRA_DETECTED_LANG = "detected_lang"
        const val EXTRA_VTT_PATH = "vtt_path"

        // 静态状态，供 ViewModel 在页面恢复时查询
        @Volatile var isRunning = false
            private set
        @Volatile var currentVideoName: String? = null
            private set
        @Volatile var currentProgress: Int = 0
            private set
        @Volatile var currentMessage: String = ""
            private set
    }

    @Inject
    lateinit var ffmpegSegmentedService: FFmpegSegmentedTranscriptionService

    @Inject
    lateinit var aiConfigStore: AIConfigStore

    private val serviceScope = CoroutineScope(Dispatchers.IO + Job())
    private val activeJobs = mutableMapOf<String, Job>() // 支持并行转录

    // 转录队列（不再使用，保留兼容）
    private val transcriptionQueue = mutableMapOf<String, Pair<String, String>>()
    private var currentTranscriptionId: String? = null

    // 服务状态
    private val _serviceState = MutableStateFlow<ServiceState>(ServiceState.Idle)
    val serviceState: StateFlow<ServiceState> = _serviceState.asStateFlow()

    private val binder = LocalBinder()

    inner class LocalBinder : Binder() {
        fun getService(): TranscriptionService = this@TranscriptionService
    }

    override fun onBind(intent: Intent?): IBinder = binder

    override fun onCreate() {
        super.onCreate()
        Log.d(TAG, "Service created")
        createNotificationChannel()
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        when (intent?.action) {
            ACTION_START -> {
                val videoPath = intent.getStringExtra(EXTRA_VIDEO_PATH)
                val videoName = intent.getStringExtra(EXTRA_VIDEO_NAME) ?: "视频"
                if (videoPath != null) {
                    startTranscription(videoPath, videoName)
                }
            }
            ACTION_CANCEL -> {
                cancelTranscription()
            }
        }
        return START_STICKY
    }

    /**
     * 开始转录
     */
    private fun startTranscription(videoPath: String, videoName: String) {
        Log.d(TAG, "Starting transcription for: $videoPath")

        val transcriptionId = System.currentTimeMillis().toString()

        // 直接并行执行，不再排队
        executeTranscription(transcriptionId, videoPath, videoName)
    }

    /**
     * 执行转录任务
     */
    private fun executeTranscription(
        transcriptionId: String,
        videoPath: String,
        videoName: String
    ) {
        currentTranscriptionId = transcriptionId
        isRunning = true
        currentVideoName = videoName
        currentProgress = 0
        currentMessage = "正在准备..."

        // 启动前台服务
        startForeground(NOTIFICATION_ID, createProgressNotification(videoName, 0, 0, "正在准备..."))

        val job = serviceScope.launch {
            try {
                _serviceState.value = ServiceState.Transcribing(0, 0, 0, "正在准备...")

                val config = aiConfigStore.config.first()
                val videoFile = File(videoPath)

                // 检查 API Key
                val hasGroqKey = config.groqApiKey.isNotBlank() ||
                                 (config.provider == "groq" && config.apiKey.isNotBlank())

                if (!hasGroqKey) {
                    sendErrorBroadcast("❌ 请先配置 Groq API Key\n\n获取 API Key：https://console.groq.com/keys")
                    _serviceState.value = ServiceState.Error("请先配置 Groq API Key")
                    stopForeground(STOP_FOREGROUND_REMOVE)
                    stopSelf()
                    return@launch
                }

                // 执行转录 - 使用用户指定的转录语言（如果设置了）
                val transcribeLang = config.transcribeLanguage.takeIf { it.isNotBlank() }
                val result = ffmpegSegmentedService.transcribeWithSegments(
                    videoFile,
                    config,
                    transcribeLang,
                    onProgress = { segment, total, progress, message, remainingSeconds ->
                        updateProgress(videoName, segment, total, progress, message)
                        sendProgressBroadcast(segment, total, progress, message, remainingSeconds)
                        _serviceState.value = ServiceState.Transcribing(
                            segment, total, progress, message
                        )
                    }
                )

                // 转录完成
                if (result != null && result.success) {
                    val base = videoPath.substringBeforeLast(".")
                    val vttPath = base + ".vtt"
                    val wtsPath = base + ".wordts.json"

                    // 如果字幕文件还不存在（可能是其他转录任务创建的），保存它们
                    if (!File(vttPath).exists()) {
                        saveSubtitles(result, vttPath, wtsPath)
                    }

                    sendCompletedBroadcast(true, result.detectedLang, result.text, videoPath, vttPath)
                    _serviceState.value = ServiceState.Completed(
                        result.detectedLang,
                        result.text
                    )

                    updateNotificationComplete(videoName)
                    delay(3000) // 显示完成通知3秒

                    // 移除已完成的任务，检查是否还有活跃任务
                    activeJobs.remove(transcriptionId)
                    if (activeJobs.isEmpty()) {
                        isRunning = false
                        currentVideoName = null
                        stopForeground(STOP_FOREGROUND_REMOVE)
                        stopSelf()
                    }

                } else {
                    val error = result?.error ?: "未知错误"
                    sendErrorBroadcast(error)
                    _serviceState.value = ServiceState.Error(error)

                    activeJobs.remove(transcriptionId)
                    if (activeJobs.isEmpty()) {
                        isRunning = false
                        currentVideoName = null
                        stopForeground(STOP_FOREGROUND_REMOVE)
                        stopSelf()
                    }
                }

            } catch (e: Exception) {
                Log.e(TAG, "Transcription error", e)
                val error = "转录失败: ${e.message}"
                sendErrorBroadcast(error)
                _serviceState.value = ServiceState.Error(error)

                activeJobs.remove(transcriptionId)
                if (activeJobs.isEmpty()) {
                    isRunning = false
                    currentVideoName = null
                    stopForeground(STOP_FOREGROUND_REMOVE)
                    stopSelf()
                }
            }
        }
        activeJobs[transcriptionId] = job
    }

    /**
     * 取消转录
     */
    private fun cancelTranscription() {
        activeJobs.values.forEach { it.cancel() }
        activeJobs.clear()
        isRunning = false
        currentVideoName = null
        currentProgress = 0
        currentMessage = ""
        _serviceState.value = ServiceState.Idle
        stopForeground(STOP_FOREGROUND_REMOVE)
        stopSelf()
        Log.d(TAG, "All transcriptions cancelled")
    }

    /**
     * 保存字幕文件
     */
    private suspend fun saveSubtitles(
        result: WhisperResult,
        vttPath: String,
        wtsPath: String
    ) = withContext(Dispatchers.IO) {
        val vttBuilder = StringBuilder("WEBVTT\n\n")
        val allWordTimings = mutableListOf<WordTimestamp>()

        if (result.words.isNotEmpty()) {
            var curWords = mutableListOf<WordTimestamp>()
            for (wt in result.words) {
                curWords.add(wt)
                if (wt.w.trim().matches(Regex(".*[.!?。！？]$")) && curWords.isNotEmpty()) {
                    val sentText = curWords.joinToString(" ") { it.w }
                    val sStart = curWords.first().s
                    val sEnd = curWords.last().e
                    vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
                    allWordTimings.addAll(curWords)
                    curWords = mutableListOf()
                }
            }
            if (curWords.isNotEmpty()) {
                val sentText = curWords.joinToString(" ") { it.w }
                val sStart = curWords.first().s
                val sEnd = curWords.last().e
                vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
                allWordTimings.addAll(curWords)
            }
        }

        File(vttPath).writeText(vttBuilder.toString())
        if (allWordTimings.isNotEmpty()) {
            val json = Json { ignoreUnknownKeys = true }
            File(wtsPath).writeText(json.encodeToString(ListSerializer(WordTimestamp.serializer()), allWordTimings))
        }

        Log.d(TAG, "Subtitles saved: ${allWordTimings.size} words")
    }

    private fun updateProgress(videoName: String, segment: Int, total: Int, progress: Int, message: String) {
        val notification = createProgressNotification(videoName, segment, total, message)
        val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    private fun updateNotificationComplete(videoName: String) {
        val notification = createCompleteNotification(videoName)
        val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    private fun sendProgressBroadcast(segment: Int, total: Int, progress: Int, message: String, remaining: Long) {
        // 更新静态状态供页面恢复时查询
        currentProgress = progress
        currentMessage = message

        val intent = Intent(ACTION_PROGRESS).apply {
            putExtra(EXTRA_SEGMENT, segment)
            putExtra(EXTRA_TOTAL, total)
            putExtra(EXTRA_PROGRESS, progress)
            putExtra(EXTRA_MESSAGE, message)
            putExtra(EXTRA_REMAINING, remaining)
        }
        sendBroadcast(intent)

        // 同时发送队列状态广播
        sendQueueUpdateBroadcast()
    }

    /**
     * 发送队列状态广播
     */
    private fun sendQueueUpdateBroadcast() {
        val queueList = transcriptionQueue.values.map { it.second }.toTypedArray()
        val intent = Intent(ACTION_QUEUE_UPDATE).apply {
            putExtra(EXTRA_QUEUE_SIZE, transcriptionQueue.size)
            putExtra(EXTRA_CURRENT_VIDEO, currentTranscriptionId)
            putExtra(EXTRA_QUEUE_LIST, queueList)
        }
        sendBroadcast(intent)
    }

    private fun sendCompletedBroadcast(success: Boolean, detectedLang: String, text: String, videoPath: String? = null, vttPath: String? = null) {
        val intent = Intent(ACTION_COMPLETED).apply {
            putExtra(EXTRA_SUCCESS, success)
            putExtra(EXTRA_DETECTED_LANG, detectedLang)
            // 计算字幕数量（粗略估计：按句子分割）
            val subtitleCount = text.split(Regex("[.!?。！？]")).filter { it.isNotBlank() }.size
            putExtra(EXTRA_SUBTITLE_COUNT, subtitleCount)
            videoPath?.let { putExtra(EXTRA_VIDEO_PATH, it) }
            vttPath?.let { putExtra(EXTRA_VTT_PATH, it) }
        }
        sendBroadcast(intent)
    }

    private fun sendErrorBroadcast(error: String) {
        val intent = Intent(ACTION_COMPLETED).apply {
            putExtra(EXTRA_SUCCESS, false)
            putExtra(EXTRA_ERROR, error)
        }
        sendBroadcast(intent)
    }

    /**
     * 创建通知渠道
     */
    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                CHANNEL_NAME,
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "显示视频转录进度"
                setShowBadge(false)
            }
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    /**
     * 创建进度通知
     */
    private fun createProgressNotification(
        videoName: String,
        segment: Int,
        total: Int,
        message: String
    ): Notification {
        val openIntent = Intent(this, com.multilanglearner.MainActivity::class.java).apply {
            action = ACTION_OPEN
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        val openPendingIntent = PendingIntent.getActivity(
            this, 0, openIntent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )

        val cancelIntent = Intent(this, TranscriptionService::class.java).apply {
            action = ACTION_CANCEL
        }
        val cancelPendingIntent = PendingIntent.getService(
            this, 0, cancelIntent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )

        val progressText = if (total > 1) {
            "分段 $segment/$total ($message)"
        } else {
            message
        }

        return NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("正在转录: $videoName")
            .setContentText(progressText)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setOngoing(true)
            .setAutoCancel(false)
            .setContentIntent(openPendingIntent)
            .addAction(android.R.drawable.ic_menu_close_clear_cancel, "取消", cancelPendingIntent)
            .setProgress(total, segment, false)
            .build()
    }

    /**
     * 创建完成通知
     */
    private fun createCompleteNotification(videoName: String): Notification {
        val openIntent = Intent(this, com.multilanglearner.MainActivity::class.java).apply {
            action = ACTION_OPEN
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP
        }
        val openPendingIntent = PendingIntent.getActivity(
            this, 0, openIntent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )

        return NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("转录完成")
            .setContentText("$videoName 已完成转录")
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setOngoing(false)
            .setAutoCancel(true)
            .setContentIntent(openPendingIntent)
            .build()
    }

    override fun onDestroy() {
        super.onDestroy()
        activeJobs.values.forEach { it.cancel() }
        activeJobs.clear()
        serviceScope.cancel()
        Log.d(TAG, "Service destroyed")
    }
}

/**
 * 服务状态
 */
sealed class ServiceState {
    object Idle : ServiceState()
    data class Transcribing(
        val segment: Int,
        val total: Int,
        val progress: Int,
        val message: String
    ) : ServiceState()
    data class Completed(
        val detectedLang: String,
        val text: String
    ) : ServiceState()
    data class Error(
        val error: String
    ) : ServiceState()
}

