459→    val words = subtitle.text.split(Regex("\\s+")).filter { it.isNotBlank() }
460→    val answers = remember(subtitle) { words.map { it.replace(Regex("[^\\p{L}\\p{M}'-]"), "") } }
461→    val inputs = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
462→    val results = remember(subtitle) { mutableStateListOf(*Array(words.size) { "" }) }
463→
464→    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
