479→                                singleLine = true,
480→                                isError = results[i] == "wrong",
481→                                colors = OutlinedTextFieldDefaults.colors(
482→                                    focusedBorderColor = if (results[i] == "correct") Color.Green else MaterialTheme.colorScheme.primary
483→                                )
484→                            )
485→                            if (results[i] == "wrong") {
486→                                Text(answers[i], color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.labelSmall)
487→                            }
488→                            TextButton(onClick = { onLookup(word.replace(Regex("[^\\p{L}\\p{M}'-]"), "")) }) {
489→                                Text("查词", style = MaterialTheme.typography.labelSmall)
490→                            }
491→                        }
492→                    }
493→                }
494→            }
495→        }
496→
497→        Spacer(Modifier.height(12.dp))
498→
499→        // Control buttons
500→        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
501→            Button(onClick = { onSpeak(subtitle.text) }) {
502→                Icon(Icons.Default.VolumeUp, null, Modifier.size(16.dp))
503→                Spacer(Modifier.width(4.dp))
504→                Text("朗读")
505→            }
506→            Button(onClick = {
507→                answers.forEachIndexed { i, answer ->
508→                    results[i] = if (inputs[i].trim().equals(answer, ignoreCase = true)) "correct" else "wrong"
509→                }
510→            }) {
511→                Icon(Icons.Default.Check, null, Modifier.size(16.dp))
512→                Spacer(Modifier.width(4.dp))
513→                Text("检查")
514→            }
515→            Button(onClick = {
516→                inputs.indices.forEach { inputs[it] = "" }
517→                results.indices.forEach { results[it] = "" }
518→                onNext()
519→            }) {
520→                Icon(Icons.Default.ArrowForward, null, Modifier.size(16.dp))
521→                Spacer(Modifier.width(4.dp))
522→                Text("下一句")
523→            }
524→        }
525→    }
526→}
527→
528→private fun formatTime(ms: Long): String {
529→    val totalSec = ms / 1000
530→    val m = totalSec / 60
531→    val s = totalSec % 60
532→    return "$m:${s.toString().padStart(2, '0')}"
533→}
